package ua.university.sms.model.entity;
import jakarta.persistence.*;import jakarta.validation.constraints.*;import java.util.*;
@Entity public class Course{@Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id;@NotBlank @Size(min=2,max=200) private String title;@Min(1)@Max(30) private int credits;private String semester;@ManyToOne(optional=false) private Teacher teacher;@OneToMany(mappedBy="course",cascade=CascadeType.REMOVE) private List<Enrollment> enrollments=new ArrayList<>(); public Long getId(){return id;}public void setId(Long id){this.id=id;}public String getTitle(){return title;}public void setTitle(String title){this.title=title;}public int getCredits(){return credits;}public void setCredits(int credits){this.credits=credits;}public String getSemester(){return semester;}public void setSemester(String semester){this.semester=semester;}public Teacher getTeacher(){return teacher;}public void setTeacher(Teacher teacher){this.teacher=teacher;}}
